  import sailpoint.object.Custom;
  import java.util.List;
  import java.util.ArrayList;
  
/*******************************************************************
   Returns Custom Object List
********************************************************************/
  public List getCustomLObjectist(String keyName, String customObjectName){
   
     List customObjectList = new ArrayList();
	 
     Custom customObject = context.getObjectByName(Custom.class,customObjectName);
 
      if (customObject != null) {
 
              customObjectList = customObject.get(keyName);
 
      } else {
	     return customObjectList;
  }
    return customObjectList;
  }
